const holdings = $('Read Holdings').all().map(i => i.json);
const config = $('Workflow Settings').first().json;

return [
  {
    json: {
      holdings,
      config
    }
  }
];

const data = $input.first().json;
const holdings = data.holdings || [];
const config = data.config || {};
const targets = config.targets || [];

if (!holdings.length) {
  return [{
    json: {
      valid: false,
      error: 'No holdings found.',
      holdings,
      config
    }
  }];
}

if (!targets.length) {
  return [{
    json: {
      valid: false,
      error: 'Targets are missing in workflow settings.',
      holdings,
      config
    }
  }];
}

const targetTotal = targets.reduce((sum, t) => sum + Number(t.target_pct || 0), 0);
if (targetTotal !== 100) {
  return [{
    json: {
      valid: false,
      error: `Target allocation must total 100. Current total is ${targetTotal}.`,
      holdings,
      config
    }
  }];
}

const seenAssets = new Set();

for (const h of holdings) {
  const asset = String(h.asset || '').trim();
  const units = Number(h.units);
  const price = Number(h.price);

  if (!asset) {
    return [{
      json: {
        valid: false,
        error: 'One holding has a blank asset name.',
        holdings,
        config
      }
    }];
  }

  if (seenAssets.has(asset)) {
    return [{
      json: {
        valid: false,
        error: `Duplicate asset found in holdings: ${asset}`,
        holdings,
        config
      }
    }];
  }
  seenAssets.add(asset);

  if (Number.isNaN(units) || units < 0) {
    return [{
      json: {
        valid: false,
        error: `Invalid units for asset: ${asset}`,
        holdings,
        config
      }
    }];
  }

  if (Number.isNaN(price) || price < 0) {
    return [{
      json: {
        valid: false,
        error: `Invalid price for asset: ${asset}`,
        holdings,
        config
      }
    }];
  }

  const target = targets.find(t => String(t.asset || '').trim() === asset);
  if (!target) {
    return [{
      json: {
        valid: false,
        error: `No target config found for asset: ${asset}`,
        holdings,
        config
      }
    }];
  }
}

return [{
  json: {
    valid: true,
    error: null,
    holdings,
    config
  }
}];

const data = $input.first().json;
const holdings = data.holdings;
const config = data.config;

const enrichedHoldings = holdings.map(h => {
  const units = Number(h.units);
  const price = Number(h.price);
  const current_value = Number(h.current_value ?? (units * price));

  return {
    row_number: h.row_number,
    asset: h.asset,
    units,
    price,
    current_value,
    last_updated: h.last_updated
  };
});

const total_value = enrichedHoldings.reduce((sum, h) => sum + h.current_value, 0);

const assets = enrichedHoldings.map(h => {
  const target = config.targets.find(t => t.asset === h.asset);

  if (!target) {
    throw new Error(`Missing target config for asset: ${h.asset}`);
  }

  const actual_pct = total_value === 0 ? 0 : (h.current_value / total_value) * 100;

  return {
    ...h,
    actual_pct,
    target_pct: Number(target.target_pct),
    min_pct: Number(target.min_pct),
    max_pct: Number(target.max_pct)
  };
});

return [{
  json: {
    holdings: assets,
    total_value,
    config
  }
}];

const data = $input.first().json;
const holdings = data.holdings;
const total_value = data.total_value;
const config = data.config;

let rebalance_needed = false;

const assets = holdings.map(h => {
  const deviation_pct = h.actual_pct - h.target_pct;
  const target_value = total_value * (h.target_pct / 100);
  const adjustment_amount = Math.abs(h.current_value - target_value);

  let status = 'within_range';
  let suggested_action = 'Hold';

  if (h.actual_pct > h.max_pct) {
    status = 'overweight';
    suggested_action = 'Reduce';
    rebalance_needed = true;
  } else if (h.actual_pct < h.min_pct) {
    status = 'underweight';
    suggested_action = 'Increase';
    rebalance_needed = true;
  }

  return {
    ...h,
    deviation_pct,
    target_value,
    adjustment_amount,
    status,
    suggested_action
  };
});

const affected_assets = assets
  .filter(a => a.status !== 'within_range')
  .map(a => a.asset);

return [{
  json: {
    total_value,
    assets,
    affected_assets,
    rebalance_needed,
    config
  }
}];

const data = $input.first().json;
const assets = data.assets;
const config = data.config;

const maxDeviation = Math.max(...assets.map(a => Math.abs(a.deviation_pct)));

let severity = 'low';
if (maxDeviation > Number(config.severity_rules.medium_max)) {
  severity = 'high';
} else if (maxDeviation > Number(config.severity_rules.low_max)) {
  severity = 'medium';
}

return [{
  json: {
    ...data,
    severity,
    max_deviation: maxDeviation
  }
}];

const data = $input.first().json;

const affected = data.assets
  .filter(a => a.status !== 'within_range')
  .map(a => `${a.asset}: ${a.status}, actual ${a.actual_pct.toFixed(2)}%, target ${a.target_pct.toFixed(2)}%, deviation ${a.deviation_pct.toFixed(2)}%, action ${a.suggested_action}, amount ${data.config.currency} ${a.adjustment_amount.toFixed(2)}`)
  .join('\n');

const ai_input = `
You are a financial portfolio monitoring assistant.

Your task is to convert structured portfolio rebalance data into a professional alert message.

STRICT RULES:
- Use only the numbers provided below
- Do NOT recalculate anything
- Do NOT invent any values
- Keep the message concise, clear and professional
- Use plain text only
- Mention severity naturally

DATA:
Portfolio Name: ${data.config.portfolio_name}
Currency: ${data.config.currency}
Total Portfolio Value: ${data.total_value}
Severity: ${data.severity}
Maximum Deviation: ${data.max_deviation.toFixed(2)}%

Assets requiring rebalance:
${affected}

OUTPUT FORMAT:
Write a clean paragraph-style alert message suitable for email.
`;

return [{
  json: {
    ...data,
    ai_input
  }
}];
